// Generated by GitHub Copilot
import { useCallback, useEffect, useMemo, useState } from "react";
import "./App.css";

const API_BASE_URL = import.meta.env.VITE_API_URL || "http://127.0.0.1:8000";
const PAGE_SIZE = 10;

const TASK_TYPE_OPTIONS = [
    "classification",
    "regression",
    "clustering",
    "time_series",
    "matrix_factorization",
    "anomaly",
];

const SAMPLE_ROWS = [
    { brightness: 0.82, density: 0.21, motion_score: 0.61, label: 1, zone: "gate-a" },
    { brightness: 0.74, density: 0.17, motion_score: 0.52, label: 1, zone: "gate-a" },
    { brightness: 0.48, density: 0.11, motion_score: 0.23, label: 0, zone: "yard" },
    { brightness: 0.59, density: 0.19, motion_score: 0.44, label: 0, zone: "yard" },
    { brightness: 0.9, density: 0.29, motion_score: 0.78, label: 1, zone: "dock" },
];

const SAMPLE_CANDIDATES = [
    {
        candidate_id: "frame_0001",
        image_uri: "local://sample/frame_0001.jpg",
        predicted_label: "person",
        confidence: 0.88,
        bbox: [41, 31, 168, 229],
    },
    {
        candidate_id: "frame_0002",
        image_uri: "local://sample/frame_0002.jpg",
        predicted_label: "motorbike",
        confidence: 0.76,
        bbox: [71, 40, 242, 268],
    },
];

/**
 * Parse user JSON text and validate it resolves to an array payload.
 * @param {string} text - JSON text from textarea input.
 * @param {string} label - Human label used in error messaging.
 * @returns {Array} Parsed array payload.
 */
function parseArrayJson(text, label) {
    const parsed = JSON.parse(text);
    if (!Array.isArray(parsed)) {
        throw new Error(`${label} must be a JSON array.`);
    }
    return parsed;
}

/**
 * Build a typed API error using backend response metadata.
 * @param {Response} response - Failed fetch response.
 * @returns {Promise<Error>} Enriched error object.
 */
async function buildApiError(response) {
    let detail = `Request failed with status ${response.status}`;

    try {
        const payload = await response.json();
        if (typeof payload?.detail === "string" && payload.detail.trim()) {
            detail = payload.detail;
        }
    } catch {
        // Use the fallback status message when response body is not JSON.
    }

    const error = new Error(detail);
    error.httpStatus = response.status;
    return error;
}

/**
 * Execute API request with timeout and optional retry policy.
 * @param {string} path - API path beginning with '/'.
 * @param {object} options - Request options.
 * @returns {Promise<any>} Parsed JSON payload.
 */
async function requestJson(
    path,
    {
        method = "GET",
        body,
        headers,
        timeoutMs = 12000,
        retries = 0,
    } = {}
) {
    let attempt = 0;
    while (attempt <= retries) {
        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), timeoutMs);

        try {
            const response = await fetch(`${API_BASE_URL}${path}`, {
                method,
                headers: {
                    ...(body ? { "Content-Type": "application/json" } : {}),
                    ...headers,
                },
                body: body ? JSON.stringify(body) : undefined,
                signal: controller.signal,
            });

            if (!response.ok) {
                throw await buildApiError(response);
            }

            if (response.status === 204) {
                return null;
            }

            return await response.json();
        } catch (requestError) {
            const isHttpError = Boolean(requestError && typeof requestError === "object" && "httpStatus" in requestError);
            const canRetry = !isHttpError && method === "GET" && attempt < retries;

            if (!canRetry) {
                if (requestError?.name === "AbortError") {
                    throw new Error("Request timed out. Please try again.");
                }
                throw requestError;
            }

            const delayMs = 250 * (attempt + 1);
            await new Promise((resolve) => setTimeout(resolve, delayMs));
        } finally {
            clearTimeout(timeoutId);
        }

        attempt += 1;
    }

    throw new Error("Request failed after retries.");
}

/**
 * Return unreviewed candidates by comparing task corrections to candidate ids.
 * @param {object} task - Annotation task payload.
 * @returns {Array} Pending candidates.
 */
function getPendingCandidates(task) {
    const corrected = new Set((task.corrections || []).map((item) => item.candidate_id));
    return (task.candidates || []).filter((candidate) => !corrected.has(candidate.candidate_id));
}

/**
 * Convert backend status to display-friendly text.
 * @param {string} status - Backend status value.
 * @returns {string} Human-readable status label.
 */
function formatStatusLabel(status) {
    return (status || "unknown").replace("_", " ");
}

/**
 * Main UI for diagnostics, recommendation ranking, and annotation review loop.
 * @returns {JSX.Element} Application root element.
 */
function App() {
    const [datasetRowsText, setDatasetRowsText] = useState(JSON.stringify(SAMPLE_ROWS, null, 2));
    const [targetColumn, setTargetColumn] = useState("label");
    const [taskType, setTaskType] = useState("classification");
    const [diagnostics, setDiagnostics] = useState(null);
    const [recommendations, setRecommendations] = useState([]);

    const [datasetName, setDatasetName] = useState("surveillance-dataset-v1");
    const [annotationModelName, setAnnotationModelName] = useState("yolov5s");
    const [candidatesText, setCandidatesText] = useState(JSON.stringify(SAMPLE_CANDIDATES, null, 2));
    const [annotationTasks, setAnnotationTasks] = useState([]);
    const [taskStatusFilter, setTaskStatusFilter] = useState("all");
    const [taskOffset, setTaskOffset] = useState(0);
    const [taskHasMore, setTaskHasMore] = useState(false);

    const [busyAction, setBusyAction] = useState("");
    const [queueLoading, setQueueLoading] = useState(false);
    const [error, setError] = useState("");
    const [success, setSuccess] = useState("");
    const [connectionState, setConnectionState] = useState("checking");

    const isBusy = queueLoading || Boolean(busyAction);

    const diagnosticsCards = useMemo(() => {
        if (!diagnostics) {
            return [];
        }
        return [
            { title: "Rows", value: diagnostics.row_count },
            { title: "Columns", value: diagnostics.column_count },
            { title: "Hints", value: diagnostics.task_hints?.length || 0 },
            {
                title: "Target Correlations",
                value: Object.keys(diagnostics.correlation_to_target || {}).length,
            },
        ];
    }, [diagnostics]);

    const queueStats = useMemo(() => {
        const completed = annotationTasks.filter((task) => task.status === "completed").length;
        const inReview = annotationTasks.filter((task) => task.status === "in_review").length;
        const pending = annotationTasks.filter((task) => task.status === "pending").length;

        return {
            total: annotationTasks.length,
            completed,
            inReview,
            pending,
        };
    }, [annotationTasks]);

    /**
     * Load annotation queue with optional offset pagination and filtering.
     * @param {object} options - Loading options.
     * @returns {Promise<void>} Completion signal.
     */
    const loadAnnotationTasks = useCallback(async ({ append = false, offset = 0, status = "all", showSuccessMessage = false } = {}) => {
        setQueueLoading(true);
        if (!append) {
            setTaskOffset(0);
        }

        try {
            const statusQuery = status === "all" ? "" : `&status=${encodeURIComponent(status)}`;
            const payload = await requestJson(`/annotations/tasks?limit=${PAGE_SIZE}&offset=${offset}${statusQuery}`, {
                retries: 1,
            });

            const tasks = payload?.tasks || [];
            const total = Number(payload?.total || 0);

            setAnnotationTasks((previous) => (append ? [...previous, ...tasks] : tasks));

            const consumed = offset + tasks.length;
            setTaskOffset(consumed);
            setTaskHasMore(consumed < total);
            setConnectionState("online");

            if (showSuccessMessage) {
                setSuccess("Annotation queue updated.");
            }
        } catch (requestError) {
            const message = requestError instanceof Error ? requestError.message : "Failed to load annotation tasks";
            setError(message);

            const isHttpError = Boolean(requestError && typeof requestError === "object" && "httpStatus" in requestError);
            setConnectionState(isHttpError ? "online" : "offline");
        } finally {
            setQueueLoading(false);
        }
    }, []);

    useEffect(() => {
        loadAnnotationTasks({ append: false, offset: 0, status: taskStatusFilter });
    }, [loadAnnotationTasks, taskStatusFilter]);

    /**
     * Trigger diagnostics computation for tabular rows.
     * @returns {Promise<void>} Completion signal.
     */
    const handleRunDiagnostics = useCallback(async () => {
        setBusyAction("Running diagnostics");
        setError("");
        setSuccess("");

        try {
            const rows = parseArrayJson(datasetRowsText, "Dataset rows");
            const payload = await requestJson("/diagnostics", {
                method: "POST",
                body: {
                    rows,
                    target_column: targetColumn || null,
                },
            });

            setDiagnostics(payload);
            setSuccess("Diagnostics computed successfully.");
            setConnectionState("online");
        } catch (requestError) {
            setError(requestError instanceof Error ? requestError.message : "Diagnostics request failed");
            const isHttpError = Boolean(requestError && typeof requestError === "object" && "httpStatus" in requestError);
            setConnectionState(isHttpError ? "online" : "offline");
        } finally {
            setBusyAction("");
        }
    }, [datasetRowsText, targetColumn]);

    /**
     * Rank model families using previously computed diagnostics.
     * @returns {Promise<void>} Completion signal.
     */
    const handleRecommendModels = useCallback(async () => {
        if (!diagnostics) {
            setError("Run diagnostics before requesting recommendations.");
            return;
        }

        setBusyAction("Ranking models");
        setError("");
        setSuccess("");

        try {
            const payload = await requestJson("/recommendations", {
                method: "POST",
                body: {
                    task_type: taskType,
                    diagnostics,
                    objective: "maximize annotation throughput with strong model fit",
                },
            });

            setRecommendations(payload.recommendations || []);
            setSuccess("Model families ranked successfully.");
            setConnectionState("online");
        } catch (requestError) {
            setError(requestError instanceof Error ? requestError.message : "Recommendation request failed");
            const isHttpError = Boolean(requestError && typeof requestError === "object" && "httpStatus" in requestError);
            setConnectionState(isHttpError ? "online" : "offline");
        } finally {
            setBusyAction("");
        }
    }, [diagnostics, taskType]);

    /**
     * Create a new annotation task from JSON candidate input.
     * @returns {Promise<void>} Completion signal.
     */
    const handleCreateTask = useCallback(async () => {
        setBusyAction("Creating annotation task");
        setError("");
        setSuccess("");

        try {
            const candidates = parseArrayJson(candidatesText, "Candidates");
            await requestJson("/annotations/tasks", {
                method: "POST",
                body: {
                    dataset_name: datasetName,
                    model_name: annotationModelName,
                    candidates,
                },
            });

            await loadAnnotationTasks({ append: false, offset: 0, status: taskStatusFilter });
            setSuccess("Annotation task created successfully.");
            setConnectionState("online");
        } catch (requestError) {
            setError(requestError instanceof Error ? requestError.message : "Task creation failed");
            const isHttpError = Boolean(requestError && typeof requestError === "object" && "httpStatus" in requestError);
            setConnectionState(isHttpError ? "online" : "offline");
        } finally {
            setBusyAction("");
        }
    }, [annotationModelName, candidatesText, datasetName, loadAnnotationTasks, taskStatusFilter]);

    /**
     * Submit approval for a pending candidate on a specific task.
     * @param {number} taskId - Task identifier.
     * @param {object} candidate - Candidate to approve.
     * @returns {Promise<void>} Completion signal.
     */
    const handleApproveCandidate = useCallback(async (taskId, candidate) => {
        setBusyAction("Submitting correction");
        setError("");
        setSuccess("");

        try {
            await requestJson(`/annotations/tasks/${taskId}/corrections`, {
                method: "POST",
                body: {
                    corrections: [
                        {
                            candidate_id: candidate.candidate_id,
                            final_label: candidate.predicted_label,
                            approved: true,
                            notes: "approved from dashboard",
                        },
                    ],
                },
            });

            await loadAnnotationTasks({ append: false, offset: 0, status: taskStatusFilter });
            setSuccess(`Candidate ${candidate.candidate_id} approved.`);
            setConnectionState("online");
        } catch (requestError) {
            setError(requestError instanceof Error ? requestError.message : "Correction submission failed");
            const isHttpError = Boolean(requestError && typeof requestError === "object" && "httpStatus" in requestError);
            setConnectionState(isHttpError ? "online" : "offline");
        } finally {
            setBusyAction("");
        }
    }, [loadAnnotationTasks, taskStatusFilter]);

    /**
     * Refresh queue using current status filter.
     * @returns {Promise<void>} Completion signal.
     */
    const handleRefreshQueue = useCallback(async () => {
        setError("");
        setSuccess("");
        await loadAnnotationTasks({ append: false, offset: 0, status: taskStatusFilter, showSuccessMessage: true });
    }, [loadAnnotationTasks, taskStatusFilter]);

    /**
     * Load the next annotation queue page.
     * @returns {Promise<void>} Completion signal.
     */
    const handleLoadMoreTasks = useCallback(async () => {
        if (!taskHasMore || queueLoading) {
            return;
        }
        await loadAnnotationTasks({ append: true, offset: taskOffset, status: taskStatusFilter });
    }, [loadAnnotationTasks, queueLoading, taskHasMore, taskOffset, taskStatusFilter]);

    return (
        <main className="app-shell" aria-busy={isBusy}>
            <header className="hero-card">
                <div className="hero-copy">
                    <p className="eyebrow">Automated ML Assistant</p>
                    <h1>Production Console For Diagnostics And Annotation Throughput</h1>
                    <p>
                        Analyze dataset quality, rank model families from telemetry, and close annotation loops with
                        fast queue operations.
                    </p>
                </div>

                <aside className="hero-meta" aria-label="Runtime status">
                    <p className={`connection-badge connection-${connectionState}`}>
                        API {connectionState === "checking" ? "checking" : connectionState}
                    </p>
                    <p className="hero-endpoint">Endpoint: {API_BASE_URL}</p>
                    {isBusy && (
                        <p className="working-text">
                            <span className="spinner" aria-hidden="true" />
                            {busyAction || "Refreshing queue"}
                        </p>
                    )}
                </aside>
            </header>

            <section className="summary-grid" aria-label="Queue summary cards">
                <article className="summary-card">
                    <h2>Total Tasks</h2>
                    <p>{queueStats.total}</p>
                </article>
                <article className="summary-card">
                    <h2>Pending</h2>
                    <p>{queueStats.pending}</p>
                </article>
                <article className="summary-card">
                    <h2>In Review</h2>
                    <p>{queueStats.inReview}</p>
                </article>
                <article className="summary-card">
                    <h2>Completed</h2>
                    <p>{queueStats.completed}</p>
                </article>
            </section>

            <section className="panel-grid">
                <article className="panel">
                    <h2>1. Dataset Diagnostics</h2>

                    <label htmlFor="target-column">Target Column</label>
                    <input
                        id="target-column"
                        value={targetColumn}
                        onChange={(event) => setTargetColumn(event.target.value)}
                    />

                    <label htmlFor="dataset-json">Dataset Rows JSON</label>
                    <textarea
                        id="dataset-json"
                        value={datasetRowsText}
                        onChange={(event) => setDatasetRowsText(event.target.value)}
                        rows={12}
                    />

                    <div className="button-row">
                        <button type="button" onClick={handleRunDiagnostics} disabled={isBusy}>
                            {busyAction === "Running diagnostics" ? "Running..." : "Run Diagnostics"}
                        </button>
                    </div>

                    {diagnosticsCards.length > 0 && (
                        <div className="kpi-grid" aria-live="polite">
                            {diagnosticsCards.map((card) => (
                                <div className="kpi" key={card.title}>
                                    <div className="kpi-title">{card.title}</div>
                                    <div className="kpi-value">{card.value}</div>
                                </div>
                            ))}
                        </div>
                    )}

                    {diagnostics?.task_hints?.length > 0 && (
                        <ul className="hint-list">
                            {diagnostics.task_hints.map((hint) => (
                                <li key={hint}>{hint}</li>
                            ))}
                        </ul>
                    )}
                </article>

                <article className="panel">
                    <h2>2. Model Family Recommendations</h2>

                    <label htmlFor="task-type">Task Type</label>
                    <select id="task-type" value={taskType} onChange={(event) => setTaskType(event.target.value)}>
                        {TASK_TYPE_OPTIONS.map((option) => (
                            <option key={option} value={option}>
                                {option}
                            </option>
                        ))}
                    </select>

                    <div className="button-row">
                        <button
                            type="button"
                            onClick={handleRecommendModels}
                            disabled={isBusy || !diagnostics}
                        >
                            {busyAction === "Ranking models" ? "Ranking..." : "Rank Models"}
                        </button>
                    </div>

                    <div className="recommendation-list" aria-live="polite">
                        {recommendations.length === 0 && (
                            <p className="placeholder">No recommendations yet. Run diagnostics before ranking models.</p>
                        )}
                        {recommendations.map((item) => (
                            <article className="recommendation" key={item.model_family}>
                                <div className="recommendation-title">{item.model_family}</div>
                                <div className="recommendation-score">Score: {item.score.toFixed(3)}</div>
                                <p>{item.rationale}</p>
                            </article>
                        ))}
                    </div>
                </article>
            </section>

            <section className="panel">
                <h2>3. Annotation Assistant</h2>

                <div className="form-grid">
                    <div>
                        <label htmlFor="dataset-name">Dataset Name</label>
                        <input
                            id="dataset-name"
                            value={datasetName}
                            onChange={(event) => setDatasetName(event.target.value)}
                        />
                    </div>

                    <div>
                        <label htmlFor="annotation-model">Pre-label Model</label>
                        <input
                            id="annotation-model"
                            value={annotationModelName}
                            onChange={(event) => setAnnotationModelName(event.target.value)}
                        />
                    </div>
                </div>

                <label htmlFor="candidates-json">Candidate JSON</label>
                <textarea
                    id="candidates-json"
                    value={candidatesText}
                    onChange={(event) => setCandidatesText(event.target.value)}
                    rows={8}
                />

                <div className="queue-toolbar">
                    <div>
                        <label htmlFor="task-status-filter">Queue Filter</label>
                        <select
                            id="task-status-filter"
                            value={taskStatusFilter}
                            onChange={(event) => setTaskStatusFilter(event.target.value)}
                        >
                            <option value="all">all</option>
                            <option value="pending">pending</option>
                            <option value="in_review">in_review</option>
                            <option value="completed">completed</option>
                        </select>
                    </div>
                    <div className="button-row compact">
                        <button type="button" onClick={handleCreateTask} disabled={isBusy}>
                            {busyAction === "Creating annotation task" ? "Creating..." : "Create Task"}
                        </button>
                        <button type="button" onClick={handleRefreshQueue} disabled={isBusy}>
                            {queueLoading ? "Refreshing..." : "Refresh Queue"}
                        </button>
                    </div>
                </div>

                <div className="task-list" aria-live="polite">
                    {annotationTasks.length === 0 && (
                        <p className="placeholder">No annotation tasks found for the selected filter.</p>
                    )}

                    {annotationTasks.map((task) => {
                        const pending = getPendingCandidates(task);
                        const completion = task.candidates.length
                            ? Math.round((task.corrections_count / task.candidates.length) * 100)
                            : 0;

                        return (
                            <article className="task-card" key={task.task_id}>
                                <div className="task-head">
                                    <h3>
                                        Task #{task.task_id} - {task.dataset_name}
                                    </h3>
                                    <span className={`status status-${task.status}`}>
                                        {formatStatusLabel(task.status)}
                                    </span>
                                </div>

                                <p>
                                    Model: {task.model_name} - Candidates: {task.candidates.length} - Corrections:{" "}
                                    {task.corrections_count}
                                </p>

                                <div className="task-progress">
                                    <div className="task-progress-label">Completion {completion}%</div>
                                    <progress value={completion} max="100" />
                                </div>

                                {pending.length > 0 ? (
                                    <div className="pending-box">
                                        <strong>Next Pending Candidate</strong>
                                        <span>
                                            {pending[0].candidate_id} ({pending[0].predicted_label})
                                        </span>
                                        <button
                                            type="button"
                                            onClick={() => handleApproveCandidate(task.task_id, pending[0])}
                                            disabled={isBusy}
                                        >
                                            {busyAction === "Submitting correction" ? "Submitting..." : "Approve Next Candidate"}
                                        </button>
                                    </div>
                                ) : (
                                    <p className="placeholder">All candidates reviewed for this task.</p>
                                )}
                            </article>
                        );
                    })}
                </div>

                {taskHasMore && (
                    <div className="load-more-wrap">
                        <button type="button" onClick={handleLoadMoreTasks} disabled={queueLoading || isBusy}>
                            {queueLoading ? "Loading..." : "Load More Tasks"}
                        </button>
                    </div>
                )}
            </section>

            {(error || success) && (
                <section className="flash-wrap" aria-live="polite" aria-atomic="true">
                    {error && (
                        <p className="flash flash-error" role="alert">
                            {error}
                        </p>
                    )}
                    {success && (
                        <p className="flash flash-success" role="status">
                            {success}
                        </p>
                    )}
                </section>
            )}
        </main>
    );
}

export default App;
